const intent = $json.intent || '';
const params = $json.intentParams || {};
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY || '';
const accessToken = $env.GOOGLE_ACCESS_TOKEN || '';

if (!GOOGLE_API_KEY && !accessToken) {
  return [{ json: { ...$json, responseText: '⚠️ Google API credentials not configured.', success: false } }];
}

let endpoint, queryParams, method = 'GET', body = null;
const calendarId = params.calendar_id || 'primary';
const authHeader = accessToken ? { Authorization: `Bearer ${accessToken}` } : {};

if (intent === 'calendar_list') {
  endpoint = `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events`;
  const now = new Date();
  const timeMin = params.time_min || now.toISOString();
  const timeMax = params.time_max || new Date(now.getTime() + 7 * 86400000).toISOString();
  queryParams = { maxResults: Math.min(params.max_results || 10, 50), timeMin, timeMax, orderBy: 'startTime', singleEvents: true };
} else if (intent === 'calendar_create') {
  const { summary, start, end, description, location, attendees } = params;
  if (!summary || !start || !end) {
    return [{ json: { ...$json, responseText: '❗ summary, start, and end are required.', success: false } }];
  endpoint = `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events`;
  method = 'POST';
  body = { summary, start: { dateTime: start }, end: { dateTime: end } };
  if (description) body.description = description;
  if (location) body.location = location;
  if (attendees) body.attendees = attendees;
} else if (intent === 'calendar_delete') {
  const eventId = params.event_id || params.id;
  if (!eventId) return [{ json: { ...$json, responseText: '❗ Event ID required.', success: false } }];
  endpoint = `https://www.googleapis.com/calendar/v3/calendars/${calendarId}/events/${eventId}`;
  method = 'DELETE';
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown Calendar intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams, apiMethod: method, apiBody: body } }];

const items = $json.items || [];
if ($json.id && ($json.status === 'cancelled' || $json.summary)) {
  // Create or delete result
  return [{ json: { ...$input.item.json, responseText: '✅ Calendar operation completed successfully.', success: true } }];
}
if (items.length === 0) {
  return [{ json: { ...$input.item.json, responseText: '📅 No upcoming events found.', success: true } }];
}
let text = '📅 Upcoming Events:

';
items.forEach((ev, i) => {
  const start = ev.start?.dateTime || ev.start?.date || 'TBD';
  const summary = ev.summary || 'Untitled';
  const location = ev.location ? `\n📍 ${ev.location}` : '';
  text += `<b>${start}</b>\n✅ ${summary}${location}\n\n`;
});
return [{ json: { ...$input.item.json, responseText: text, success: true } }];
